AirplaneConfig = {}
AirplaneConfig.Airplane = {}
AirplaneConfig.CurAirplane = 0

function AirplaneConfig:init(config)
    RandomUtil:setRandomSeed()
    local data = {}
    for id, airplane in pairs(config) do
        local item = {}
        item.id = tonumber(id)
        local spos = StringUtil.split(airplane.startPos, "#")
        item.startPos = VectorUtil.newVector3(spos[1], spos[2], spos[3])
        local epos = StringUtil.split(airplane.endPos, "#")
        item.endPos = VectorUtil.newVector3(epos[1], epos[2], epos[3])
        item.speed = tonumber(airplane.speed)
        item.horizontalSpeed = tonumber(airplane.horizontalSpeed)
        item.verticalSpeed = tonumber(airplane.verticalSpeed)
        item.height = math.min(tonumber(spos[2]), tonumber(epos[2]))
        self.Airplane[item.id] = item
        table.insert(data, item.id)
    end

    RandomUtil:initRandomSeed("airplane", data)
    self:randomAirplane()
end

function AirplaneConfig:randomAirplane()
    self.CurAirplane = RandomUtil:get("airplane")
    local airplane = self:getAirplane()
    HostApi.setFallingSpeed(airplane.horizontalSpeed, airplane.verticalSpeed)
end

function AirplaneConfig:getAirplane()
    local airplane = self.Airplane[self.CurAirplane]
    if next(airplane) ~= nil then
        return airplane
    end
    return self.Airplane[1]
end

function AirplaneConfig:setAirplane()
    local airplane = self:getAirplane()
    EngineWorld:getWorld():addAircraft(airplane.startPos, 0)
    EngineWorld:getWorld():tryAllPlayerTakeAircraft(airplane.startPos, airplane.endPos, airplane.speed)
end

function AirplaneConfig:getFlyingTime()
    local airplane = self.Airplane[self.CurAirplane]
    local distance = math.sqrt(MathUtil:distanceSquare3d(airplane.startPos, airplane.endPos))
    local time = math.ceil(distance / airplane.speed)
    return time
end

function AirplaneConfig:ifOpenParachute(y, player)
    if y > GameConfig.forceGlideHeight and y <= GameConfig.glideHeight and not player.isParachute then
        HostApi.sendChangeAircraftUI(player.rakssid, true)
        return
    end
    if y <= GameConfig.forceGlideHeight and not player.isParachute then
        player:onOpenParachute()
    end
end